    # Procedure Handlers (v3.4.0)
    def _create_procedure(self, params, state):
        """Create a stored procedure."""
        if not self.procedure_engine:
            return "ERROR: Procedure support not available"
        
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        name = params.get('name')
        params_str = params.get('params', '')
        body = params.get('body')
        
        if not name or not body:
            return "ERROR: CREATE PROCEDURE requires name and body"
        
        try:
            # Parse parameters
            from procedure_engine import ProcedureParameter, ProcedureParameterMode
            parameters = []
            
            if params_str:
                for param_def in params_str.split(','):
                    param_def = param_def.strip()
                    if not param_def:
                        continue
                    
                    # Parse: [IN|OUT|INOUT] @name TYPE [= default]
                    import re
                    match = re.match(
                        r'(?:(IN|OUT|INOUT)\\s+)?@?(\\w+)\\s+(\\w+(?:\\([^)]*\\))?)'
                        r'(?:\\s*=\\s*(.+))?',
                        param_def,
                        re.IGNORECASE
                    )
                    
                    if match:
                        mode_str = match.group(1) or 'IN'
                        parameters.append(ProcedureParameter(
                            name=match.group(2),
                            mode=ProcedureParameterMode(mode_str.upper()),
                            data_type=match.group(3),
                            default_value=match.group(4)
                        ))
            
            procedure = self.procedure_engine.create_procedure(
                name=name,
                parameters=parameters,
                body=body
            )
            
            return f"Procedure '{name}' created with {len(parameters)} parameter(s)"
            
        except Exception as e:
            return f"ERROR: Failed to create procedure: {e}"
    
    def _drop_procedure(self, params, state):
        """Drop a stored procedure."""
        if not self.procedure_engine:
            return "ERROR: Procedure support not available"
        
        name = params.get('name')
        if not name:
            return "ERROR: DROP PROCEDURE requires procedure name"
        
        success = self.procedure_engine.drop_procedure(name)
        if success:
            return f"Procedure '{name}' dropped"
        else:
            return f"ERROR: Procedure '{name}' not found"
    
    def _call_procedure(self, params, state):
        """Execute a stored procedure."""
        if not self.procedure_engine:
            return "ERROR: Procedure support not available"
        
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        name = params.get('name')
        args_str = params.get('args', '')
        
        if not name:
            return "ERROR: CALL requires procedure name"
        
        try:
            # Parse arguments
            args = {}
            if args_str:
                for i, arg in enumerate(args_str.split(',')):
                    arg = arg.strip()
                    if '=' in arg:
                        # Named argument: param=value
                        key, value = arg.split('=', 1)
                        args[key.strip()] = self._parse_procedure_arg(value.strip())
                    else:
                        # Positional argument
                        args[f'arg_{i}'] = self._parse_procedure_arg(arg)
            
            result = self.procedure_engine.execute(name, args)
            
            # Format result
            output = [f"Procedure '{name}' executed successfully"]
            
            if result.get('return_value') is not None:
                output.append(f"Return value: {result['return_value']}")
            
            if result.get('output_params'):
                output.append("Output parameters:")
                for param, value in result['output_params'].items():
                    output.append(f"  {param} = {value}")
            
            return "\n".join(output)
            
        except Exception as e:
            return f"ERROR: Procedure execution failed: {e}"
    
    def _parse_procedure_arg(self, value: str) -> Any:
        """Parse procedure argument value."""
        value = value.strip()
        
        # String literal
        if (value.startswith("'") and value.endswith("'")) or \
           (value.startswith('"') and value.endswith('"')):
            return value[1:-1]
        
        # Number
        try:
            if '.' in value:
                return float(value)
            return int(value)
        except ValueError:
            pass
        
        # NULL
        if value.upper() == 'NULL':
            return None
        
        # Boolean
        if value.upper() == 'TRUE':
            return True
        if value.upper() == 'FALSE':
            return False
        
        return value
    
