        if not self.partition_manager:
            return "ERROR: Partition support not available"
        
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        table = params.get('table')
        definition = params.get('definition')
        
        if not table or not definition:
            return "ERROR: ADD PARTITION requires table and definition"
        
