            # Parse partition definition
            import re
            match = re.match(
                r'PARTITION\\s+(\\w+)\\s+VALUES\\s+(LESS\\s+THAN|IN)\\s*\\(([^)]+)\\)',
                definition,
                re.IGNORECASE
            )
            
            if not match:
                return "ERROR: Invalid partition definition"
            
            part_name = match.group(1)
            part_type = match.group(2).upper()
