    # Trigger Handlers (v3.4.0)
    def _create_trigger(self, params, state):
        """Create a database trigger."""
        if not self.trigger_engine:
            return "ERROR: Trigger support not available"
        
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        name = params.get('name')
        table = params.get('table')
        timing = params.get('timing')
        event = params.get('event')
        level = params.get('level')
        action = params.get('action')
        when_condition = params.get('when')
        
        if not all([name, table, timing, event, level, action]):
            return "ERROR: CREATE TRIGGER requires name, timing, event, table, level, and action"
        
        try:
            trigger = self.trigger_engine.create_trigger(
                name=name,
                table=table,
                timing=timing,
                event=event,
                level=level,
                action_body=action,
                when_condition=when_condition,
                action_type='SQL'
            )
            return f"Trigger '{name}' created on table '{table}'"
        except ValueError as e:
            return f"ERROR: {e}"
        except Exception as e:
            return f"ERROR: Failed to create trigger: {e}"
    
