    # Advanced Index Handlers (v3.4.0)
    def _create_advanced_index(self, params, state):
        """Create an advanced index."""
        if not self.advanced_index_manager:
            return "ERROR: Advanced index support not available"
        
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        name = params.get('name')
        table = params.get('table')
        columns_str = params.get('columns', '')
        is_unique = params.get('unique') is not None
        where_clause = params.get('where')
        include_str = params.get('include', '')
        
        if not name or not table or not columns_str:
            return "ERROR: CREATE INDEX requires name, table, and columns"
        
        try:
            from advanced_index import IndexType, IndexColumn
            
            # Parse columns
            columns = []
            for col in columns_str.split(','):
                col = col.strip()
                if '(' in col:  # Expression
                    columns.append(col)
                else:
                    parts = col.split()
                    col_name = parts[0]
                    order = parts[1].upper() if len(parts) > 1 else 'ASC'
                    columns.append(IndexColumn(name=col_name, order=order))
            
            # Parse include columns
            include_columns = None
            if include_str:
                include_columns = [c.strip() for c in include_str.split(',')]
            
            # Determine index type
            if where_clause:
                index_type = IndexType.PARTIAL
            elif include_columns:
                index_type = IndexType.COVERING
            else:
                index_type = IndexType.COMPOSITE
            
            # Create index
            index = self.advanced_index_manager.create_index(
                name=name,
                table=table,
                columns=columns,
                index_type=index_type,
                where_clause=where_clause,
                include_columns=include_columns,
                is_unique=is_unique
            )
            
            type_str = index_type.value.lower()
            return f"Created {type_str} index '{name}' on '{table}'"
            
        except Exception as e:
            return f"ERROR: Failed to create index: {e}"
    
    def _create_expression_index(self, params, state):
        """Create an expression index."""
        if not self.advanced_index_manager:
            return "ERROR: Advanced index support not available"
        
        name = params.get('name')
        table = params.get('table')
        expression = params.get('expression')
        
        if not all([name, table, expression]):
            return "ERROR: Expression index requires name, table, and expression"
        
        try:
            from advanced_index import IndexType
            index = self.advanced_index_manager.create_index(
                name=name,
                table=table,
                columns=[],
                index_type=IndexType.EXPRESSION,
                expressions=[expression],
                is_unique=False
            )
            
            return f"Created expression index '{name}' on '{table}' ({expression})"
            
        except Exception as e:
            return f"ERROR: Failed to create expression index: {e}"
    
    def _drop_advanced_index(self, params, state):
        """Drop an advanced index."""
        if not self.advanced_index_manager:
            return "ERROR: Advanced index support not available"
        
        name = params.get('name')
        if not name:
            return "ERROR: DROP INDEX requires index name"
        
        success = self.advanced_index_manager.drop_index(name)
        if success:
            return f"Index '{name}' dropped"
        else:
            return f"ERROR: Index '{name}' not found"
    
    def _analyze_index(self, params, state):
        """Analyze index statistics."""
        if not self.advanced_index_manager:
            return "ERROR: Advanced index support not available"
        
        name = params.get('name')
        if not name:
            return "ERROR: ANALYZE INDEX requires index name"
        
        info = self.advanced_index_manager.get_index_info(name)
        
        if not info:
            return f"ERROR: Index '{name}' not found"
        
        lines = [
            f"Index: {info['name']}",
            f"Table: {info['table']}",
            f"Type: {info['type']}",
            f"Columns: {', '.join(info['columns'])}",
            f"Selectivity: {info['selectivity']:.4f}",
            f"Size: {info['size_bytes']} bytes"
        ]
        
        if info['where_clause']:
            lines.append(f"Where: {info['where_clause']}")
        
        if info['include_columns']:
            lines.append(f"Include: {', '.join(info['include_columns'])}")
        
        return "\n".join(lines)

