    def _insert(self, params, state):
        """Execute INSERT with trigger support."""
        if not state.get('current_db'):
            return "ERROR: No database selected"
        
        table_name = params.get('table')
        values = params.get('values', [])
        
        if not table_name:
            return "ERROR: Table name required"
        
        # Fire BEFORE INSERT triggers (row level)
        if self.trigger_engine:
            from trigger_engine import TriggerEvent, TriggerTiming
            try:
                new_rows = self.trigger_engine.fire_triggers(
                    table=table_name,
                    event=TriggerEvent.INSERT,
                    timing=TriggerTiming.BEFORE,
                    new_rows=[{'value': values}]  # Simplified - would be actual row data
                )
                if not new_rows:  # Trigger cancelled operation
                    return "INSERT cancelled by trigger"
            except Exception as e:
                return f"ERROR: Trigger execution failed: {e}"
        
        # Execute INSERT
        result = self.db.insert(table_name, values)
        
        # Fire AFTER INSERT triggers
        if self.trigger_engine:
            from trigger_engine import TriggerEvent, TriggerTiming
            try:
                self.trigger_engine.fire_triggers(
                    table=table_name,
                    event=TriggerEvent.INSERT,
                    timing=TriggerTiming.AFTER,
                    new_rows=[{'value': values}]
                )
            except Exception as e:
                return f"ERROR: AFTER INSERT trigger failed: {e}"
        
        return result
